// @/src/hooks/useNotification.hook.ts
import { createContext, useContext, useState, useEffect } from 'react';
import { NotificationContext } from '@/src/contexts/Nofitication.context';
import { notify } from '../helpers/notification.helpers';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

const useNotification = (): [NotificationProps, () => Promise<void>] => {
  const notificationElem = useContext(NotificationContext);
  const [notificationProps, setNotificationProps] = useState<NotificationProps>({
    heading: '',
    subheading: '',
    type: '',
  });

  useEffect(() => {
    const handleNotification = async () => {
      try {
        await notify(notificationElem, notificationProps);
      } catch (error) {
        console.error(error);
      }
    };
    handleNotification();
  }, [notificationProps, notificationElem]);

  const triggerNotification = (props: NotificationProps) => {
    setNotificationProps(props);
  };

  return [notificationProps, triggerNotification];
};

export default useNotification;
